let interval_in_hrs= datetime_diff('hour', {TimeRange:end}, {TimeRange:start});
let interval_in_days= datetime_diff('day', {TimeRange:end}, {TimeRange:start});
let bin_duration=case(interval_in_hrs<=24, 1h, interval_in_days<=30, 1d, interval_in_days>=31 and interval_in_days<=90, 7d, 31d);
CyjaxThreatIndicator
| where ("*" in ({Indicator_Type:value}) or IndicatorType in ({Indicator_Type:value})) and (('*' == ('{Indicator_Value}') or IndicatorValue contains ('{Indicator_Value}')))
| make-series Count = count() default = 0 on TimeGenerated from {TimeRange:start} to {TimeRange:end} step bin_duration by IndicatorType
